/**
 * Strongly-typed service interface for the Gateway canister actor.
 * Used as the generic parameter to {@link Actor.createActor}.
 */
export interface GatewayService {
  /** Send a user message and get an AI reply. Update call (goes through consensus). */
  prompt: (req: CandidPromptRequest) => Promise<CandidResult<CandidPromptResponse>>;
  /** Send a dual prompt and get both fast and smart replies. Update call. */
  dualPrompt: (req: CandidPromptRequest) => Promise<{ ok: CandidDualPromptResponse } | { err: Record<string, unknown> }>;
  /** Send the same prompt to multiple models and compare responses. Update call. */
  compareModels: (req: { message: string; modelIds: string[]; conversationId: [] | [string]; systemPrompt: [] | [string]; mindspaceId: [] | [string] }) => Promise<{ ok: CandidCompareResponse } | { err: Record<string, unknown> }>;
  /** Fetch full conversation including all messages. Query call (fast, no consensus). */
  getConversation: (id: string) => Promise<CandidResult<unknown>>;
  /** List conversation summaries for the authenticated caller. */
  listConversations: () => Promise<CandidResult<unknown[]>>;
  /** Delete a conversation by ID. Requires ownership. */
  deleteConversation: (id: string) => Promise<CandidResult<null>>;
  /** Save a new system prompt template. Returns the created template. */
  saveTemplate: (name: string, content: string) => Promise<CandidResult<CandidSystemPromptTemplate>>;
  /** List all system prompt templates (built-in + user-created). */
  listTemplates: () => Promise<CandidResult<CandidSystemPromptTemplate[]>>;
  /** Delete a user-created template by ID. Built-in templates cannot be deleted. */
  deleteTemplate: (templateId: string) => Promise<CandidResult<null>>;
  /** Search conversations by message content (case-insensitive). */
  searchConversations: (query: string) => Promise<CandidResult<CandidConversationSummary[]>>;
  /** Export a conversation in JSON or Markdown format. */
  exportConversation: (convId: string, format: CandidExportFormat) => Promise<CandidResult<string>>;
  /** Query per-model fee overrides. Returns (modelKey, fee) tuples. */
  getModelFees: () => Promise<[string, bigint][]>;
  /** Send an email via Resend. Requires resend_api_key in KeyVault. */
  sendEmail: (to: string, subject: string, htmlBody: string, from: [] | [string]) => Promise<CandidCommResult>;
  /** Send an SMS via Twilio. Requires twilio credentials in KeyVault. */
  sendSms: (to: string, body: string) => Promise<CandidCommResult>;
  /** Save MagickMind configuration (mindspace + brain mode + Multi-LLM). Update call. */
  setMagickMindConfig: (mindspaceId: string, brainMode: CandidMagickMindBrainMode, fastModelId: string, smartModelIds: string[], computePower: bigint) => Promise<CandidResult<null>>;
  /** Get the caller's MagickMind configuration. Query call. */
  getMagickMindConfig: () => Promise<CandidResult<CandidMagickMindConfig>>;
  /** Save or update a persona. Pass [] for new, [id] to update. */
  savePersona: (
    personaId: [] | [string],
    name: string,
    avatar: string,
    description: string,
    personality: string,
    tone: string,
    expertise: string[],
    instructions: string
  ) => Promise<{ ok: CandidPersona } | { err: Record<string, unknown> }>;
  /** List all personas (built-in + user-created). */
  listPersonas: () => Promise<{ ok: CandidPersona[] } | { err: Record<string, unknown> }>;
  /** Get a single persona by ID. */
  getPersona: (id: string) => Promise<{ ok: CandidPersona } | { err: Record<string, unknown> }>;
  /** Delete a user-created persona by ID. */
  deletePersona: (id: string) => Promise<{ ok: null } | { err: Record<string, unknown> }>;
  /** Compile a persona into a system prompt string. */
  compilePersona: (id: string) => Promise<{ ok: string } | { err: Record<string, unknown> }>;
  /** Get persona traits including growth config and evolution state. */
  getPersonaTraits: (personaId: string) => Promise<{ ok: CandidPersonaTraits } | { err: Record<string, unknown> }>;
  /** Save persona traits with growth config and optional Multi-LLM config. */
  savePersonaTraits: (personaId: string, traits: CandidPersonaTrait[], growthConfig: CandidGrowthConfig, multiLlmConfig: [] | [CandidMultiLlmConfig]) => Promise<{ ok: CandidPersonaTraits } | { err: Record<string, unknown> }>;
  /** Trigger trait evolution based on conversation summary. */
  evolvePersonaTraits: (personaId: string, summary: string) => Promise<{ ok: CandidPersonaTraits } | { err: Record<string, unknown> }>;
  /** Create a new group chat with selected personas and turn order. */
  createGroupChat: (name: string, personaIds: string[], turnOrder: CandidTurnOrder) => Promise<{ ok: CandidGroupChat } | { err: Record<string, unknown> }>;
  /** List all group chats for the caller. */
  listGroupChats: () => Promise<{ ok: CandidGroupChat[] } | { err: Record<string, unknown> }>;
  /** Delete a group chat by ID. */
  deleteGroupChat: (id: string) => Promise<{ ok: null } | { err: Record<string, unknown> }>;
  /** Send a message to a group chat, receiving responses from all personas (or targeted persona). */
  groupPrompt: (req: { groupId: string; conversationId: [] | [string]; message: string; mindspaceId: [] | [string]; targetPersonaId: [] | [string] }) => Promise<{ ok: CandidGroupPromptResponse } | { err: Record<string, unknown> }>;
  /** Invite a human user (by Principal) to a group chat. */
  inviteToGroupChat: (groupId: string, invitee: Principal) => Promise<{ ok: null } | { err: Record<string, unknown> }>;
  /** Query a corpus with semantic search. */
  queryCorpus: (corpusId: string, query: string, mode: string, onlyContext: boolean) => Promise<CandidMemoryResult>;
  /** Compose chat history + corpus + pelican into unified context. */
  prepareContext: (mindspaceId: string, historyLimit: bigint, corpusQuery: [] | [string], pelicanQuery: [] | [string]) => Promise<CandidMemoryResult>;
  /** Create a new knowledge base corpus. */
  createCorpus: (name: string, description: string) => Promise<CandidMemoryResult>;
  /** List all corpora for the authenticated user. */
  listCorpora: () => Promise<CandidMemoryResult>;
  /** Delete a corpus by ID. */
  deleteCorpus: (corpusId: string) => Promise<CandidMemoryResult>;
  /** Get a presigned S3 upload URL for a file. */
  presignUpload: (fileName: string, contentType: string, sizeBytes: bigint, corpusId: [] | [string]) => Promise<CandidMemoryResult>;
  /** Add an uploaded artifact to a corpus for ingestion. */
  addArtifactToCorpus: (corpusId: string, artifactId: string) => Promise<CandidMemoryResult>;
  /** Get the ingestion status of an artifact in a corpus. */
  getIngestionStatus: (corpusId: string, artifactId: string) => Promise<CandidMemoryResult>;
  /** List all mindspaces for the authenticated user. */
  listMindspaces: () => Promise<CandidMemoryResult>;
  /** Create a new mindspace. */
  createMindspace: (name: string, description: string, corpusIds: string[], msType: string) => Promise<CandidMemoryResult>;
  /** Prepare a MagickMind persona for use. */
  mmPreparePersona: (personaId: string) => Promise<CandidMemoryResult>;
  /** List all versions of a MagickMind persona. */
  mmListPersonaVersions: (personaId: string) => Promise<CandidMemoryResult>;
  /** Get the active version of a MagickMind persona. */
  mmGetActivePersonaVersion: (personaId: string) => Promise<CandidMemoryResult>;
  /** Get the effective (runtime-blended) personality for a persona. */
  mmGetEffectivePersonality: (personaId: string) => Promise<CandidMemoryResult>;
  /** List all available persona blueprints. */
  mmListBlueprints: () => Promise<CandidMemoryResult>;
  /** Get a blueprint by its key. */
  mmGetBlueprintByKey: (key: string) => Promise<CandidMemoryResult>;
  /** Hydrate a blueprint to see full trait definitions. */
  mmHydrateBlueprint: (blueprintId: string) => Promise<CandidMemoryResult>;
  /** List all server-side traits. */
  mmListTraits: () => Promise<CandidMemoryResult>;
  /** Get paginated messages from a mindspace. */
  mmGetMessages: (mindspaceId: string, limit: bigint, order: string, cursor: [] | [string]) => Promise<CandidMemoryResult>;
  /** Add a participant to a mindspace. */
  mmAddParticipant: (mindspaceId: string, userId: string, role: string) => Promise<CandidMemoryResult>;
  /** Create a new persona from a blueprint. */
  mmCreatePersonaFromBlueprint: (blueprintId: string, name: string, description: string) => Promise<CandidMemoryResult>;
  /** Invalidate the MagickMind runtime cache. */
  mmInvalidateCache: () => Promise<CandidMemoryResult>;
  // Marketplace
  publishPersona: (personaId: string, pricePerMessage: bigint, pricePerDay: bigint, corpusIds: string[], category: CandidMarketplaceCategory) => Promise<CandidMarketplaceOpResult>;
  unpublishPersona: (personaId: string) => Promise<CandidMarketplaceOpResult>;
  browseMarketplace: (category: string, sortBy: string, offset: bigint, limit: bigint) => Promise<CandidMarketplaceListing[]>;
  hirePersona: (personaId: string, paymentType: CandidPaymentType) => Promise<CandidMarketplaceOpResult>;
  endHire: (personaId: string) => Promise<CandidMarketplaceOpResult>;
  listMyHires: () => Promise<CandidPersonaHire[]>;
  ratePersona: (personaId: string, rating: bigint) => Promise<CandidMarketplaceOpResult>;
  getPersonaEarnings: (personaId: string) => Promise<CandidMarketplaceOpResult>;
  withdrawPersonaEarnings: (personaId: string, amount: bigint) => Promise<CandidMarketplaceOpResult>;
  mintPersonaNft: (personaId: string) => Promise<CandidMarketplaceOpResult>;
  getPersonaNft: (personaId: string) => Promise<[] | [CandidPersonaNftMetadata]>;
  /** Canister health check. Returns a status string. */
  health: () => Promise<string>;
}

// ── Actor helper ────────────────────────────────────────────────────

/**
 * Create a typed actor for the Gateway canister.
 *
 * @param agent - An authenticated {@link HttpAgent} (from {@link createAgent}).
 * @param canisterId - Optional override; defaults to the build-time `VITE_GATEWAY_CANISTER_ID`.
 * @returns An {@link ActorSubclass} typed to {@link GatewayService}.
 *
 * @example
 * ```ts
 * const agent = await createAgent(authClient);
 * const gateway = createGatewayActor(agent);
 * const result = await gateway.prompt({ ... });
 * ```
 */
export function createGatewayActor(
  agent: HttpAgent,
  canisterId?: string,
): ActorSubclass<GatewayService> {
  return Actor.createActor<GatewayService>(idlFactory, {
    agent,
    canisterId: canisterId ?? GATEWAY_CANISTER_ID,
  });
}
